const acts = items.map(i => i.json);
const now = new Date();

const startOfWeek = new Date(now);
startOfWeek.setDate(now.getDate() - now.getDay() + (now.getDay() === 0 ? -6 : 1));
startOfWeek.setHours(0,0,0,0);

const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
const startOfYear = new Date(now.getFullYear(), 0, 1);

const sportLabel = (t) => {
  const map = {Ride:"Rennrad",MountainBikeRide:"MTB",VirtualRide:"Virtual Ride",Run:"Laufen",Hike:"Wandern",Walk:"Gehen",Swim:"Schwimmen",WeightTraining:"Krafttraining",Workout:"Workout"};
  return map[t] || t;
};

const aggregate = (list) => {
  const byType = {};
  let totDist=0, totElev=0, totTime=0, totCount=0, totCal=0;
  for (const a of list) {
    totDist += a.distance||0;
    totElev += a.total_elevation_gain||0;
    totTime += a.moving_time||0;
    totCount++;
    totCal += a.kilojoules ? Math.round(a.kilojoules*0.239) : 0;
    const t = a.sport_type||a.type;
    if (!byType[t]) byType[t] = {count:0,distance:0,elevation:0,time:0,label:sportLabel(t)};
    byType[t].count++;
    byType[t].distance += a.distance||0;
    byType[t].elevation += a.total_elevation_gain||0;
    byType[t].time += a.moving_time||0;
  }
  return {
    count: totCount,
    distanceKm: Math.round(totDist/100)/10,
    elevationM: Math.round(totElev),
    timeMin: Math.round(totTime/60),
    calories: totCal,
    byType: Object.entries(byType).sort((a,b)=>b[1].distance-a[1].distance).map(([type,d])=>({type,label:d.label,count:d.count,distanceKm:Math.round(d.distance/100)/10,elevationM:Math.round(d.elevation),timeMin:Math.round(d.time/60)}))
  };
};

const daily = [];
for (let i = 29; i >= 0; i--) {
  const d = new Date(now); d.setDate(d.getDate()-i); d.setHours(0,0,0,0);
  const nd = new Date(d); nd.setDate(d.getDate()+1);
  const dayActs = acts.filter(a => { const ad = new Date(a.start_date); return ad>=d && ad<nd; });
  daily.push({
    date: d.toISOString().slice(0,10),
    distanceKm: Math.round(dayActs.reduce((s,a)=>s+(a.distance||0),0)/100)/10,
    count: dayActs.length,
    calories: dayActs.reduce((s,a)=>s+(a.kilojoules?Math.round(a.kilojoules*0.239):0),0)
  });
}

const weekly = [];
for (let i = 7; i >= 0; i--) {
  const sw = new Date(startOfWeek); sw.setDate(sw.getDate()-i*7);
  const ew = new Date(sw); ew.setDate(sw.getDate()+7);
  const wActs = acts.filter(a => { const ad = new Date(a.start_date); return ad>=sw && ad<ew; });
  weekly.push({
    week: sw.toISOString().slice(0,10),
    label: i===0 ? "Jetzt" : sw.toLocaleDateString("de-DE",{day:"2-digit",month:"2-digit"}),
    distanceKm: Math.round(wActs.reduce((s,a)=>s+(a.distance||0),0)/100)/10,
    count: wActs.length,
    timeMin: Math.round(wActs.reduce((s,a)=>s+(a.moving_time||0),0)/60)
  });
}

const recent = acts.slice(0,10).map(a => ({
  id: a.id,
  name: a.name,
  type: a.sport_type||a.type,
  label: sportLabel(a.sport_type||a.type),
  date: a.start_date_local||a.start_date,
  distanceKm: Math.round((a.distance||0)/100)/10,
  elevationM: Math.round(a.total_elevation_gain||0),
  timeMin: Math.round((a.moving_time||0)/60),
  avgSpeedKmh: a.average_speed ? Math.round(a.average_speed*36)/10 : null,
  avgHr: a.average_heartrate ? Math.round(a.average_heartrate) : null,
  calories: a.kilojoules ? Math.round(a.kilojoules*0.239) : null,
  kudos: a.kudos_count||0,
  stravaUrl: "https://www.strava.com/activities/"+a.id
}));

return [{ json: { week: aggregate(acts.filter(a=>new Date(a.start_date)>=startOfWeek)), month: aggregate(acts.filter(a=>new Date(a.start_date)>=startOfMonth)), year: aggregate(acts.filter(a=>new Date(a.start_date)>=startOfYear)), recent, daily, weekly, updatedAt: new Date().toISOString() } }];

